enum risicoNiveau { Laag, Verhoogd, Kritiek };
static void Main(string[] args)
{
    const int arrayLengte = 100;
    bool afsluiten = false;

    while (!afsluiten)
    {
        int nummerPersoon = 0;
        string[] namen = new string[arrayLengte];
        string[] namenAnoniem = new string[namen.Length];
        bool[] toegelatenArray = new bool[namen.Length];

        for (int i = 0; i &lt; namen.Length; i++)
        {
            namen[i] = "leeg";
        }

        Console.Clear();
        bool herhalen = true;
        while (herhalen)
        {
            Console.WriteLine($"Voer de naam in van persoon {nummerPersoon + 1}");
            string naam = Console.ReadLine().ToLower();
            if (naam == "stop")
            {
                herhalen = false;
            }
            else
            {
                namen[nummerPersoon] = naam;
                bool goedAntwoord = true;

                do
                {
                    Console.WriteLine("Werd deze persoon toegelaten? j/n");
                    string keuze = Console.ReadLine().ToLower();
                    switch (keuze)
                    {
                        case "j":
                            goedAntwoord = true;
                            toegelatenArray[nummerPersoon] = true;
                            break;
                        case "n":
                            goedAntwoord = true;
                            toegelatenArray[nummerPersoon] = false;
                            break;
                        default:
                            goedAntwoord = false;
                            break;
                    }
                } while (!goedAntwoord);
                if (toegelatenArray[nummerPersoon])
                {
                    Console.WriteLine($"De persoon met naam {namen[nummerPersoon]} werd ingevoerd. Hij werd toegelaten");
                }
                else
                {
                    Console.WriteLine($"De persoon met naam {namen[nummerPersoon]} werd ingevoerd. Hij werd niet toegelaten");
                }
                nummerPersoon++;
            }

        }
        ToonTracerRapport(namen, toegelatenArray);
        Console.WriteLine("Moeten de gebruikersnamen anoniem gemaakt worden? j/n");
        if (Console.ReadLine().ToLower() == "j")
        {
            namenAnoniem = MaakAnoniem(namen, toegelatenArray);
            ToonTracerRapport(namenAnoniem, toegelatenArray);
        }
        Console.WriteLine("Wilt u afsluiten? j/n");
        if (Console.ReadLine().ToLower() == "j")
        {
            afsluiten = true;
        }
    }

}
static void ToonTracerRapport(string[] namenArray, bool[] toegelatenArray)
{
    int aantalPersonen = 0;
    int aantalNietToegelaten = 0;
    double procentNietToegelaten = 0;
    risicoNiveau risico = risicoNiveau.Laag;
    const double kritiek = 0.75;
    const double verhoogd = 0.35;

    for (int i = 0; i &lt; toegelatenArray.Length; i++)
    {
        if (!toegelatenArray[i] && namenArray[i] != "leeg")
        {
            aantalNietToegelaten++;
        }
        else if (toegelatenArray[i] && namenArray[i] != "leeg")
        {
            aantalPersonen++;
        }
    }
    procentNietToegelaten = Convert.ToDouble(aantalNietToegelaten) / aantalPersonen;
    if (procentNietToegelaten &gt; kritiek)
    {
        risico = risicoNiveau.Kritiek;
    }
    else if (procentNietToegelaten &gt; verhoogd)
    {
        risico = risicoNiveau.Verhoogd;
    }
    Console.Clear();
    Console.WriteLine($"Aantal ingevoerde personen = {aantalPersonen}");
    Console.WriteLine($"Daarvan werden er {aantalNietToegelaten} personen niet toegelaten, dat is {procentNietToegelaten:P}.");
    Console.WriteLine($"Risico : {risico}\n");

    Console.WriteLine("Volgende personen werden niet toegelaten:");
    for (int i = 0; i &lt; aantalPersonen; i++)
    {
        if (!toegelatenArray[i] && namenArray[i] != "leeg")
        {
            Console.WriteLine($"- {namenArray[i]}");
        }
    }
}
static string[] MaakAnoniem(string[] namen, bool[] toegelatenArray)
{
    string[] anoniemeNamen = new string[namen.Length];
    Array.Copy(namen, anoniemeNamen, namen.Length);
    for (int i = 0; i &lt; anoniemeNamen.Length; i++)
    {
        if (namen[i] != "leeg")
        {
            if (!toegelatenArray[i] && namen[i] != "leeg")
            {
                anoniemeNamen[i] = "*****";
            }
        }

    }
    return anoniemeNamen;
}

Info
Ga ervan uit dat de gebruiker géén foute invoer doet.

Opgave
Volgende methode kan je gebruiken om het IP-adres van je computer te verkrijgen. Deze methode zal je IP-adres teruggeven als een array van 4 strings. Als je adres het volgende is “192.168.1.100”, dan zal de methode dit teruggeven als de stringarray met de waarden: “192”,“168”,“1”,“100”.
static string[] VerkrijgIP()
{
    try
    {
        var host = Dns.GetHostEntry(Dns.GetHostName());
        foreach (var ip in host.AddressList)
        {
            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                return ip.ToString().Split(".");
            }
        }
        return new string[] { "0","0","0","0"}; //indien geen adres gevonden
    }
    catch (Exception ex)
    {
        return new string[] { "0", "0", "0", "0" };
    }
}
Gebruik deze methode om volgende zaken te doen (OPGELET: bovenstaande methodecode mag NIET aangepast worden):

Basis informatie
In het hoofdprogramma gebeuren volgende zaken:

Je toont je eigen IP-adres (verkregen via de VerkrijgIP methode), waarbij je een punt plaatst tussen ieder deel, bijvoorbeeld: “192.168.1.100”.
Je toont het masker, waarbij we veronderstellen dat het laatste element uit de array het masker is. Dit laatste deel tonen we als “x” .Als ons huidige IP adres “10.3.34.234” is dan tonen we: “10.3.34.x”.



Hulp-methoden
Maak een aantal hulpmethoden aan (bepaald zelf return type en eventuele parameters), met volgende eigenschappen.

IsLokaal: deze methode controleert of een meegegeven IP-adres uit een lokaal netwerk komt. Een IP-adres is lokaal indien het eerste van de 4 delen 10 of 192 is. “10.34.42.2” is dus een lokaal adres. “34.10.12.111” is geen lokaal adres.
ToonOmgekeerd: deze methode toont het meegegeven IP-adres omgekeerd op het scherm. “192.168.1.100” wordt dan “100.1.168.192” op het scherm.
IsCorrectAdres: deze methode controleert of een meegegeven IP-adres een legaal adres is. Een IP-adres is geldig indien ieder deel een getal is tussen 1 tot en met 254. Volgende adres is dus geen correct adres “192.304.2.6”, vanwege het tweede deel dat hoger is dan 254.
IsGelijk: deze methode zal laten weten of 2 meegegeven IP-adressen identiek zijn.
VerhoogAdres: deze methode zal het meegegeven IP-adres met eentje verhogen. Het zal het achterste getal met 1 verhogen. Indien het getal op 255 komt, dan wordt dit getal terug 1 (je hoeft niets met het 2e getal te doen). “192.168.1.100” zal “192.168.1.101” worden. “192.157.23.254” zal “192.157.23.1” worden. Het nieuwe adres wordt terug als een string-array gegeven uit de methode.

