            return veiligheidsNetten;
        }
    }

    public DeadWall(bool heeftVeiligheidsnetten) : base(21)
    {
        veiligheidsNetten = heeftVeiligheidsnetten;
        tekenChar = 'M';
    }
    public override int BerekenMoeilijkheidsgraad()
