static double Roulette(double startKapitaal, int aantalSim = 10)
{
    Random rng = new Random();
    double eindKapitaal = startKapitaal;
    for (int i = 0; i &lt; aantalSim; i++)
    {
        if (rng.Next(0, 60) == rng.Next(0, 60))
        {
            eindKapitaal++;
        }
        else
            eindKapitaal -= 0.1;
    }
    return eindKapitaal;
}

