        {
            if (value &gt;= 20 && value &lt;= 80)
                base.Price = value;
        }
    }

    class CoffeeTableBook : Book
    {
        public override double Price
        {
            get { return base.Price; }
            set
            {
                if (value &gt;= 35 && value &lt;= 100)
                    base.Price = value;
            }
        }
    }
}

